import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polarflow import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutTracker:
    def __init__(self, strava_token, polar_flow_token, myfitnesspal_token):
        self.strava_client = Client(access_token=strava_token)
        self.polar_flow_client = PolarFlow(polar_flow_token)
        self.myfitnesspal_client = MyFitnessPal(myfitnesspal_token)
        self.workouts = []
        self.nutrition = []

    def import_strava_workouts(self):
        activities = self.strava_client.get_activities()
        for activity in activities:
            workout = {
                'date': activity.start_date,
                'sport': activity.type,
                'distance': activity.distance.get_num(),
                'time': activity.elapsed_time.total_seconds(),
                'heart_rate': activity.average_heartrate
            }
            self.workouts.append(workout)

    def import_polar_flow_workouts(self):
        workouts = self.polar_flow_client.get_workouts()
        for workout in workouts:
            activity = {
                'date': workout['date'],
                'sport': workout['sport'],
                'distance': workout['distance'],
                'time': workout['duration'],
                'heart_rate': workout['heart_rate']
            }
            self.workouts.append(activity)

    def import_myfitnesspal_nutrition(self):
        nutrition = self.myfitnesspal_client.get_nutrition()
        for entry in nutrition:
            nutrition_entry = {
                'date': entry['date'],
                'calories': entry['calories'],
                'protein': entry['protein'],
                'carbohydrates': entry['carbohydrates'],
                'fat': entry['fat']
            }
            self.nutrition.append(nutrition_entry)

    def aggregate_heart_rate(self):
        heart_rate_zones = {}
        for workout in self.workouts:
            if workout['heart_rate']:
                if workout['heart_rate'] < 120:
                    zone = 'low'
                elif workout['heart_rate'] < 140:
                    zone = 'moderate'
                else:
                    zone = 'high'
                if zone in heart_rate_zones:
                    heart_rate_zones[zone] += workout['time']
                else:
                    heart_rate_zones[zone] = workout['time']
        return heart_rate_zones

    def plot_progress(self, metric):
        if metric == 'pace':
            x = [workout['date'] for workout in self.workouts]
            y = [workout['distance'] / workout['time'] for workout in self.workouts]
        elif metric == 'mileage':
            x = [workout['date'] for workout in self.workouts]
            y = [workout['distance'] for workout in self.workouts]
        plt.plot(x, y)
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

    def dashboard(self):
        print('Workouts:')
        for workout in self.workouts:
            print(f"Date: {workout['date']}, Sport: {workout['sport']}, Distance: {workout['distance']}, Time: {workout['time']}, Heart Rate: {workout['heart_rate']}")
        print('Nutrition:')
        for entry in self.nutrition:
            print(f"Date: {entry['date']}, Calories: {entry['calories']}, Protein: {entry['protein']}, Carbohydrates: {entry['carbohydrates']}, Fat: {entry['fat']}")
        heart_rate_zones = self.aggregate_heart_rate()
        print('Heart Rate Zones:')
        for zone, time in heart_rate_zones.items():
            print(f"{zone.capitalize()}: {time} seconds")
        metric = input("Enter 'pace' or 'mileage' to plot progress: ")
        self.plot_progress(metric)

