    myfitnesspal_token = 'your_myfitnesspal_token'
    tracker = WorkoutTracker(strava_token, polar_flow_token, myfitnesspal_token)
    tracker.import_strava_workouts()
    tracker.import_polar_flow_workouts()
    tracker.import_myfitnesspal_nutrition()
    tracker.dashboard()

if __name__ == '__main__':
